import requests

def get_top_python_repos(count=10):
    try:
        response = requests.get(
            'https://api.github.com/search/repositories',
            params={
                'q': 'language:python',
                'sort': 'stars',
                'order': 'desc',
                'per_page': count
            },
            headers={'Accept': 'application/vnd.github.v3+json'},
            timeout=10
        )
        response.raise_for_status()
        data = response.json()

        print(f'Found {data["total_count"]:,} Python repos\n')
        for i, repo in enumerate(data['items'], 1):
            print(f'{i}. {repo["full_name"]}')
            print(f'   Stars: {repo["stargazers_count"]:,}')
            print(f'   {repo["description"][:80] if repo["description"] else "No description"}')
            print()

    except requests.exceptions.Timeout:
        print('Request timed out')
    except requests.exceptions.HTTPError as e:
        print(f'HTTP Error: {e.response.status_code}')
    except requests.exceptions.RequestException as e:
        print(f'Error: {e}')

get_top_python_repos()
